            model,
            global_tables,
            columns,
            ports,
            input_fields,
            params,
            aggs: Vec::new(),
            inputs: Vec::new(),
        };
        this.collect_all()?;
        Ok(this)
    }

    fn collect_all(&mut self) -> Result<(), CudaError> {
        for validated in self.model.transitions() {
