            let value = match &destination.ty {
                AttrType::Ref { .. } => PendingColumn::Ref(
                    eval_typed_ref_column(value, table, snapshot, params, &mut cache)?.values,
                ),
                _ => PendingColumn::Value(eval_column(
                    value,
                    table.with_expected_attr(attr)?,
                    snapshot,
                    params,
                    &mut cache,
                )?),
            };
