        }
        for candidate_index in winner_indices {
            let candidate = &candidates[candidate_index];
            for (attr_index, values) in &effect_columns {
                pending.push(PendingWrite {
                    box_index,
                    table_index,
                    attr_index: *attr_index,
                    row: candidate.row,
                    value: values.at(candidate.row)?,
