1506	  const long long min = (-0x7fffffffffffffffLL - 1LL);
1507	  const long long max = 0x7fffffffffffffffLL;
1508	  if (a == 0 || b == 0) return 0;
1509	  if ((a == min && b == -1) || (b == min && a == -1)) { *error = 1; return 0; }
1510	  if (a > 0) {
1511	    if ((b > 0 && a > max / b) || (b < 0 && b < min / a)) { *error = 1; return 0; }
