 120	    lambda: f64,
 121	) -> f64 {
 122	    if lambda <= 0.0 {
 123	        f64::INFINITY
 124	    } else {
 125	        -uniform_f64(seed, tick, rule_id, entity_id, draw_idx).ln() / lambda
 126	    }
