1539	                                ((unsigned long long)counter[1] >> 11);
1540	  double sample = ((double)mantissa + 0.5) * (1.0 / 9007199254740992.0);
1541	  return sample == 1.0 ? sembla_f64(0x3fefffffffffffffULL) : sample;
1542	}
