 108	/// Samples an exponential racing-clock delay at rate `lambda`.
 109	///
 110	/// For positive rates this computes `-ln(U) / lambda`, where `U` is the open
 111	/// uniform sample for the same coordinates. Per `DESIGN.md` §4.3, non-positive
 112	/// rates return [`f64::INFINITY`], meaning that the transition never fires.
 113	#[must_use]
 114	pub fn exp_f64(
 115	    seed: u64,
 116	    tick: u32,
 117	    rule_id: u32,
 118	    entity_id: u32,
 119	    draw_idx: u32,
 120	    lambda: f64,
 121	) -> f64 {
 122	    if lambda <= 0.0 {
 123	        f64::INFINITY
 124	    } else {
 125	        -uniform_f64(seed, tick, rule_id, entity_id, draw_idx).ln() / lambda
 126	    }
 127	}
