 317	    pub fn philox_vectors(
 318	        &self,
 319	        coordinates: &[PhiloxCoordinate],
 320	    ) -> Result<Vec<[u32; 4]>, CudaError> {
 321	        if coordinates.is_empty() {
 322	            return Ok(Vec::new());
 323	        }
 324	        let count = u32::try_from(coordinates.len()).map_err(|_| {
 325	            CudaError::InvalidInput("Philox vector count exceeds u32 capacity".to_owned())
 326	        })?;
 327	        let seeds = coordinates
 328	            .iter()
 329	            .map(|value| value.seed)
 330	            .collect::<Vec<_>>();
 331	        let ticks = coordinates
 332	            .iter()
 333	            .map(|value| value.tick)
 334	            .collect::<Vec<_>>();
 335	        let rules = coordinates
 336	            .iter()
 337	            .map(|value| value.rule_id)
 338	            .collect::<Vec<_>>();
 339	        let entities = coordinates
 340	            .iter()
 341	            .map(|value| value.entity_id)
 342	            .collect::<Vec<_>>();
 343	        let draws = coordinates
 344	            .iter()
 345	            .map(|value| value.draw_index)
 346	            .collect::<Vec<_>>();
 347	        let seeds = self.stream.memcpy_stod(&seeds).map_err(driver_error)?;
 348	        let ticks = self.stream.memcpy_stod(&ticks).map_err(driver_error)?;
 349	        let rules = self.stream.memcpy_stod(&rules).map_err(driver_error)?;
 350	        let entities = self.stream.memcpy_stod(&entities).map_err(driver_error)?;
 351	        let draws = self.stream.memcpy_stod(&draws).map_err(driver_error)?;
 352	        let output_len = coordinates
 353	            .len()
 354	            .checked_mul(4)
 355	            .ok_or_else(|| CudaError::InvalidInput("Philox output size overflow".to_owned()))?;
 356	        let mut output = self
 357	            .stream
