 363	            .arg(&rules)
 364	            .arg(&entities)
 365	            .arg(&draws)
 366	            .arg(&mut output)
 367	            .arg(&count);
 368	        unsafe { args.launch(LaunchConfig::for_num_elems(count)) }.map_err(driver_error)?;
 369	        let output = self.stream.memcpy_dtov(&output).map_err(driver_error)?;
