 795	fn device_status(status: &[u64]) -> CudaError {
 796	    let message = match status[0] {
 797	        1 => format!("aggregate {} produced an out-of-range group", status[1]),
 798	        2 => format!("aggregate {} overflowed Int", status[1]),
 799	        3 => format!("candidate {} overflowed Int", status[1]),
 800	        4 => format!(
 801	            "candidates {} and {} have incompatible claim ordering",
 802	            status[1], status[2]
 803	        ),
 804	        5 => format!("candidate {} effect overflowed Int", status[1]),
 805	        6 => format!("candidate {} produced an out-of-range Enum", status[1]),
 806	        7 => format!("candidate {} produced an out-of-range Ref", status[1]),
 807	        8 => format!(
 808	            "double write at cell {} by rules {} and {}",
 809	            status[1], status[2], status[3]
 810	        ),
 811	        9 => format!("wire output field {} overflowed Int", status[1]),
 812	        10 => format!("candidate {} claim expression overflowed Int", status[1]),
 813	        code => format!("unknown device status {code}"),
 814	    };
 815	    CudaError::DeviceExecution(message)
